    IN_INVOICE_TOTAL_PERCENTAGE_INIT_SUB_PE: this.IN_INVOICE_TOTAL_PERCENTAGE_INIT_SUB_PE,
    _user:this.currentUser.id,
    IN_TEAM_ID: (this.newStatus == 'corporate') ? 'CORP' : 'CORPH',
    //IN_TEAM_ID: 'CORP',
    COPY_TEMP_COMPANY_ID : this.COPY_TEMP_COMPANY_ID,
    IN_SUMMARY_TOTAL_GRID: this.IN_SUMMARY_TOTAL_GRID,
    IN_IS_DISCREPANCY : this.IN_IS_DISCREPANCY,

    IN_IS_CO01_COH01_TASK: (task.element_name.indexOf("CO.01") != -1 || task.element_name.indexOf("COH.01") != -1) ? true : false
};
let jsonData = JSON.stringify(data);
//Encode data to make it secure
let encodedData = encodeURIComponent(jsonData);
//Get window height
let screenHeight = 1200;
if (typeof top.innerHeight != 'undefined') {
    screenHeight = top.innerHeight - 50;
}
screenHeight = 200
//let code = `<body style="margin:0px;padding:0px;overflow:hidden;width:` + screenHeight + `px">
let code = `<body style="margin:0px;padding:0px;">
    <style>
    .iframe-container {
        background:url(/public-files/loadingIMG.gif) center center no-repeat;
    }
    </style>
    <div class="iframe-container">
        <iframe id="iframe-psTools"
            src="/api/1.0/pstools/script/in---co-allocation-custom-grid?data=` + encodedData + `" frameborder="0" 
            style="overflow:hidden;overflow-x:hidden;overflow-y:hidden;height:` + screenHeight + `px;
            width:100%; top:110px;left:0px;right:0px;bottom:0px" 
        ></iframe>
    <div>
</body>`;
return code;

let btnSubmit  = this.SUBMIT_CO_FLAG;
let btnClose   = this.SUBMIT_CO;
let btnSubmitH = this.SUBMIT_COH;
let btnReturn  = this.RETURN_CASE;

//debugger;
let dataIframe = $('#iframe-psTools').contents().find('#iframe-items').val() ?? '';
if (dataIframe !='') {
    dataIframe = dataIframe;
}

let dataJson   = JSON.parse(dataIframe);
let dataString = JSON.stringify(dataJson);
let dataSerial = btoa(encodeURIComponent(dataString).replace(/%([0-9A-F]{2})/g,
        function toSolidBytes(match, p1) {
          return String.fromCharCode('0x' + p1);
        }));
return dataSerial;

let btnSubmit = this.SUBMIT_CO_FLAG;
let btnAction  = this.SUBMIT_CO;
let copySubmit = this.copySubmitForm_CO;
let btnSubmitR = this.SUBMIT_COH;
let copySubmitR = this.copySubmitForm_COH;
btnSubmitR = (btnSubmitR != copySubmitR) ? 'SUBMIT' : null;
btnSubmit = (btnSubmit != copySubmit) ? 'SUBMIT' : null;
if(btnSubmit == 'SUBMIT'){
    //let appList  = this.APPROVER_LIST_CO.DEFAULT;
    let fxAction = this.vendorInformation.IN_FX_REQUIRED;
    let venLoc   = this.vendorInformation.vendorLocation;
    if(venLoc != null && (fxAction == "Yes" || fxAction == "No")){
        setTimeout(() => {
            document.querySelectorAll('button[name="SUBMIT_CO"]')[2].click();
        }, "2500");
        btnAction = 'SUBMITR';
    }    
}

/*if(btnAction == 'SAVE'){
        let reqsID = this.REQUEST_ID; 
        let dataToUpdate = {
            "data":{
                "IN_INVOICE_VENDOR" : this.IN_INVOICE_VENDOR,
                "vendorInformation" :this.vendorInformation,
                "IN_INVOICE_TRANS_COMMENTS" :this.IN_INVOICE_TRANS_COMMENTS,
                //"APPROVER_LIST_CO" : this.APPROVER_LIST_CO,
                "IN_COMMENT_CO" : this.IN_COMMENT_CO
            }
        };
        ProcessMaker.apiClient.put('requests/'+reqsID, dataToUpdate)
        setTimeout(() => {
            location.reload();
        }, "5500");
}
if(btnAction == 'SAVE_CLOSE'){
    setTimeout(() => {
        let reqsID = this.REQUEST_ID; 
        let dataToUpdate = {
            "data":{
                "IN_INVOICE_VENDOR" : this.IN_INVOICE_VENDOR,
                "vendorInformation" :this.vendorInformation,
                "IN_INVOICE_TRANS_COMMENTS" :this.IN_INVOICE_TRANS_COMMENTS,
                //"APPROVER_LIST_CO" : this.APPROVER_LIST_CO,
                "IN_COMMENT_CO" : this.IN_COMMENT_CO
            }
        };
        ProcessMaker.apiClient.put('requests/'+reqsID, dataToUpdate)
        location.href = "/";
    }, "2500");
}*/
if(btnSubmitR == 'SUBMIT'){
    let fxAction = this.vendorInformation.IN_FX_REQUIRED;
    let action   = this.IN_SUBMITTER_COH;
    let venLoc   = this.vendorInformation.vendorLocation;
    if(venLoc != null && action != null && (fxAction == "Yes" || fxAction == "No")){
        if(action == 'Rejected' && (this.IN_COMMENT_COH == null || this.IN_COMMENT_COH == '')){
            return btnSubmitR;    
        }
        setTimeout(() => {
            document.querySelectorAll('button[name="SUBMIT_CO"]')[2].click();
        }, "2500");
        btnAction = 'SUBMITR';
    }
}
return btnAction;

let statusScrren = this.readyScreen;
if(statusScrren != null){
    setTimeout(() => {
        let sizemax = document.getElementById('iframe-psTools').contentWindow.document.body.scrollHeight;
        sizemax = sizemax + 30;
        document.getElementById("iframe-psTools").style.height = sizemax+'px';
    }, "500");
}

if(this.newStatus == "corporate"){
    return this._user.id;
}

/*let selectedUser = this.APPROVER_LIST_CO.DEFAULT.USER_ID;
return selectedUser;*/
return this._user.id;

let dataVendor = this.vendorInformation;
if(dataVendor[0] != undefined && dataVendor[0].EXPENSE_VENDOR_COMPANYCODE != undefined){
    document.getElementById("iframe-psTools").contentWindow.document.querySelector("button[id='btnGetComId']").click();
    return dataVendor[0].EXPENSE_VENDOR_COMPANYCODE;

}

let btnSubmit = this.SUBMIT_CO_FLAG;
let btnClose  = this.SUBMIT_CO;
let btnSubmitH = this.SUBMIT_COH;
let btnReturn  = this.RETURN_CASE;
//debugger;
let dataIframe = $('#iframe-psTools').contents().find('#iframe-items_2').val() ?? '';
if (dataIframe !='') {
    dataIframe = dataIframe;
}
let dataJson   = JSON.parse(dataIframe);
let dataString = JSON.stringify(dataJson);
let dataSerial = btoa(encodeURIComponent(dataString).replace(/%([0-9A-F]{2})/g,
        function toSolidBytes(match, p1) {
          return String.fromCharCode('0x' + p1);
        }));
return dataSerial;

let actionBtn = this.auxiliarGridValidation_CO;
let isValidCustomeGrid = $('#iframe-psTools').contents().find('#iframe-IN_IS_VALID_CUSTOME_GRID').val();
if(isValidCustomeGrid == 'true'){
    return true;
}
return false;

return {
    "comments" : this.IN_COMMENT_COH,
    "userID" :this._user.id,
    "userName" :this._user.fullname
};

const vendorCurrency = this.vendorInformation["0"].EXPENSE_VENDOR_CURRENCY;
let result = {};

if (this.IN_INVOICE_CURRENCY !== vendorCurrency) {
  result = {
    //message: `Please note that the currency of the selected vendor is different from the one previously registered: ` + this.IN_INVOICE_CURRENCY,
    message: `Warning: Vendor Currency and Invoice Currency are different.`,
    valid: false
  };
} else {
  result = {
    message: "",
    valid: true
  };
}

$("#iframe-psTools").contents().find(".IN_INVOICE_CURRENCY_label").text(this.IN_INVOICE_CURRENCY);

return result;

if(this.IN_INVOICE_CURRENCY){

    let currencyTmp = $("div[id*='IN_INVOICE_CURRENCY']").find(".multiselect__single").text();
    if(this.IN_INVOICE_CURRENCY == currencyTmp){
        return;
    }

    let vendorInformation = this.vendorInformation;
    //vendorInformation.IN_FX_REQUIRED = (this.IN_INVOICE_CURRENCY !== this.vendorInformation["0"].EXPENSE_VENDOR_CURRENCY) ? 'Yes' : 'No';
    vendorInformation.IN_FX_REQUIRED = (this.IN_INVOICE_CURRENCY != 'CAD' && this.IN_INVOICE_CURRENCY != 'USD' && vendorInformation[0].EXPENSE_VENDOR_COMPANYCODE == '010') ? 'Yes' : 'No';
    return vendorInformation;
}

let action = this.SUBMIT_RETURN_IS03;
let actionCopy = this.copy_SubmitReturn;
if(action != actionCopy){
    document.querySelectorAll('button[name="RETURN_CASE"]')[0].click();
}

setTimeout(() => {
    if (typeof($('button:contains("Return Case")')['0']) != "undefined") {
        $('button:contains("Return Case")').on( "click", function() {
            setTimeout(() => {
                $('#buttonCancelPopUp').on("click", function() {
                    $(".modal-header").find("button").trigger("click");
                });
                $('[selector="back_is03"]').on("click", function() {
                    document.querySelectorAll('button[name="RETURN_CASE"]')[0].click();
                    return true;
                });
            }, 100);
        });
    }
}, 500);

return {
    "id": this._user.id,
    "fullname" : this._user.fullname
}

setTimeout(() => {
    if (typeof($('button:contains("Return Case")')['0']) != "undefined") {
        $('button:contains("Return Case")').on( "click", function() {
            document.querySelector('div[selector="popUpComment"] textarea').value = ''
        });
    } else {
        console.log("NUUUUUUU");
    }
}, 500);

